import React, { useState, useEffect } from "react";
import axios from "axios";
import {
  UsersIcon,
  AcademicCapIcon,
  ChartBarIcon,
  ArrowDownTrayIcon,
} from "@heroicons/react/24/outline";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  BarChart,
  Bar,
  Legend,
  PieChart,
  Pie,
  Cell,
} from "recharts";

const PIE_COLORS = ["#10b981", "#6366f1", "#ef4444"];

export default function AdminReports() {
  const [loading, setLoading] = useState(true);

  const [users, setUsers] = useState([]);
  const [attempts, setAttempts] = useState([]);

  const [userGrowthData, setUserGrowthData] = useState([]);
  const [quizStatsData, setQuizStatsData] = useState([]);
  const [roleDistribution, setRoleDistribution] = useState([]);

  const BASE_URL = "http://localhost:8086";

  useEffect(() => {
    fetchAllData();
  }, []);

  const fetchAllData = async () => {
    try {
      const [userRes, attemptRes] = await Promise.all([
        axios.get(`${BASE_URL}/user`),
        axios.get(`${BASE_URL}/api/quiz-attempts`),
      ]);

      const usersData = userRes.data;
      const attemptsData = attemptRes.data;

      setUsers(usersData);
      setAttempts(attemptsData);

      generateAnalytics(usersData, attemptsData);
      setLoading(false);
    } catch (err) {
      console.error(err);
      setLoading(false);
    }
  };

  // 🔥 PROCESS DATA
  const generateAnalytics = (usersData, attemptsData) => {

    // 1️⃣ USER GROWTH (by month)
    const monthMap = {};

    usersData.forEach((u) => {
      if (!u.createdAt) return;

      const month = new Date(u.createdAt).toLocaleString("default", {
        month: "short",
      });

      monthMap[month] = (monthMap[month] || 0) + 1;
    });

    const growth = Object.keys(monthMap).map((m) => ({
      month: m,
      users: monthMap[m],
    }));

    setUserGrowthData(growth);

    // 2️⃣ QUIZ STATS (group by quizTitle)
    const quizMap = {};

    attemptsData.forEach((a) => {
      if (!quizMap[a.quizTitle]) {
        quizMap[a.quizTitle] = {
          subject: a.quizTitle,
          attempts: 0,
          totalScore: 0,
        };
      }

      quizMap[a.quizTitle].attempts += 1;
      quizMap[a.quizTitle].totalScore += a.percentage;
    });

    const quizStats = Object.values(quizMap).map((q) => ({
      subject: q.subject,
      attempts: q.attempts,
      avgScore: Math.round(q.totalScore / q.attempts),
    }));

    setQuizStatsData(quizStats);

    // 3️⃣ ROLE DISTRIBUTION
    const roleMap = {};

    usersData.forEach((u) => {
      roleMap[u.role] = (roleMap[u.role] || 0) + 1;
    });

    const roles = Object.keys(roleMap).map((r) => ({
      name: r,
      value: roleMap[r],
    }));

    setRoleDistribution(roles);
  };

  // 🔥 CALCULATED VALUES
  const totalUsers = users.length;
  const totalAttempts = attempts.length;

  const avgScore =
    attempts.length > 0
      ? (
          attempts.reduce((sum, a) => sum + a.percentage, 0) /
          attempts.length
        ).toFixed(1)
      : 0;

  const handleExport = () => {
    alert("Export coming soon 🚀");
  };

  if (loading) {
    return (
      <div className="min-h-screen w-[83vw] ml-[17vw] flex items-center justify-center text-white">
        Loading real data...
      </div>
    );
  }

  return (
    <div className="min-h-screen w-[83vw] ml-[17vw] bg-gradient-to-br from-slate-900 via-gray-900 to-slate-800 p-8 text-white">

      {/* HEADER */}
      <div className="flex justify-between items-center mb-8 mt-10">
        <div>
          <h1 className="text-3xl font-bold">Platform Analytics</h1>
          <p className="text-gray-400 mt-1">Real-time data</p>
        </div>

        <button
          onClick={handleExport}
          className="flex items-center gap-2 px-4 py-2 bg-indigo-600 rounded-lg"
        >
          <ArrowDownTrayIcon className="w-5 h-5" />
          Export
        </button>
      </div>

      {/* SUMMARY */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <StatCard
          title="Total Users"
          value={totalUsers}
          icon={<UsersIcon className="w-8 h-8 text-blue-400" />}
        />
        <StatCard
          title="Quiz Attempts"
          value={totalAttempts}
          icon={<AcademicCapIcon className="w-8 h-8 text-green-400" />}
        />
        <StatCard
          title="Average Score"
          value={`${avgScore}%`}
          icon={<ChartBarIcon className="w-8 h-8 text-purple-400" />}
        />
      </div>

      {/* CHARTS */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* USER GROWTH */}
        <ChartCard title="User Growth">
          <AreaChart data={userGrowthData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#ffffff1a" />
            <XAxis dataKey="month" stroke="#ccc" />
            <YAxis stroke="#ccc" />
            <Tooltip />
            <Area dataKey="users" stroke="#6366f1" fill="#6366f1" />
          </AreaChart>
        </ChartCard>

        {/* QUIZ STATS */}
        <ChartCard title="Quiz Attempts">
          <BarChart data={quizStatsData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#ffffff1a" />
            <XAxis dataKey="subject" stroke="#ccc" />
            <YAxis stroke="#ccc" />
            <Tooltip />
            <Legend />
            <Bar dataKey="attempts" fill="#34d399" />
          </BarChart>
        </ChartCard>

        {/* ROLES */}
        <ChartCard title="User Roles" full>
          <PieChart>
            <Pie data={roleDistribution} dataKey="value" outerRadius={100}>
              {roleDistribution.map((_, i) => (
                <Cell key={i} fill={PIE_COLORS[i % 3]} />
              ))}
            </Pie>
            <Tooltip />
          </PieChart>
        </ChartCard>

      </div>
    </div>
  );
}

// reusable
function StatCard({ title, value, icon }) {
  return (
    <div className="bg-white/5 p-6 rounded-xl flex justify-between">
      <div>
        <p className="text-gray-400">{title}</p>
        <h2 className="text-2xl font-bold">{value}</h2>
      </div>
      {icon}
    </div>
  );
}

function ChartCard({ title, children, full }) {
  return (
    <div className={`bg-white/5 p-6 rounded-xl ${full ? "lg:col-span-2" : ""}`}>
      <h3 className="mb-4">{title}</h3>
      <div className="h-64">
        <ResponsiveContainer width="100%" height="100%">
          {children}
        </ResponsiveContainer>
      </div>
    </div>
  );
}
